steps.script:
var tw = tree.current_scene._cycle_camera_tween
if tw == null:
	return false
return tw.is_valid() and tw.is_running()

var mn = tree.current_scene
var uid = str(mn.movement_controller.active_unit_id)
var u = GameState.get_unit(uid)
var p = null
for mdl in u.get("models", []):
	if mdl.get("alive", true):
		var pos = mdl.get("position", null)
		if pos is Dictionary and pos.has("x"):
			p = Vector2(float(pos.x), float(pos.y))
			break
		elif pos is Vector2:
			p = pos
			break
if p == null:
	return false
var vp = mn.get_viewport().get_visible_rect().size
var expected = p - vp / (2.0 * mn.view_zoom)
return mn.view_offset.distance_to(expected) < 2.0
